function solve(nums) {
    const N = nums.length;

    // Sort nums to get S (the target sorted array)
    // Use slice() to ensure the original nums array is not modified
    const S = [...nums].sort((a, b) => a - b);

    // Find all divisors k of N
    const divisors = [];
    for (let k = 1; k * k <= N; k++) {
        if (N % k === 0) {
            divisors.push(k);
            if (k * k !== N) {
                divisors.push(N / k);
            }
        }
    }

    let totalSum = 0;

    /**
     * Checks if array B is a cyclic shift of array T.
     * This implementation runs in O(k^2) time complexity.
     * @param {number[]} B - The original block.
     * @param {number[]} T - The target sorted block.
     * @returns {boolean} True if B is a cyclic shift of T.
     */
    const isCyclicShift = (B, T) => {
        const k = B.length;
        if (k === 0) return true;

        // Check all k possible rotations (shifts p=0 to k-1)
        for (let p = 0; p < k; p++) {
            let match = true;
            for (let j = 0; j < k; j++) {
                // Compare B[j] with T shifted by p: T[(p + j) % k]
                if (B[j] !== T[(p + j) % k]) {
                    match = false;
                    break;
                }
            }
            if (match) {
                return true;
            }
        }
        return false;
    };

    // Iterate through all potential sortable integers k
    for (const k of divisors) {
        let isSortable = true;
        const numBlocks = N / k;

        // Check each block i
        for (let i = 0; i < numBlocks; i++) {
            const startIdx = i * k;

            // Extract Block B_i from original nums
            const B_i = nums.slice(startIdx, startIdx + k);

            // Extract Target Block T_i from the sorted array S
            const T_i = S.slice(startIdx, startIdx + k);

            // If B_i cannot be cyclically shifted to match T_i, k is not sortable
            if (!isCyclicShift(B_i, T_i)) {
                isSortable = false;
                break;
            }
        }

        if (isSortable) {
            totalSum += k;
        }
    }

    return totalSum;
}

